# Example 78: Class with utilities; probe lives in a dedicated method

class RateLimiter:
    def __init__(self, burst: int) -> None:
        self.burst = max(1, burst)
        self.tokens = burst

    def refill(self, n: int) -> None:
        self.tokens = min(self.burst, self.tokens + n)


def client_simulation():
    limiter = RateLimiter(5)
    for _ in range(3):
        limiter.refill(1)

    under_limit = True
    throttled = False

    if under_limit:
        print("dispatch", limiter.tokens)
    print(throttled)


client_simulation()

