DEFAULTS = {"timeout_ms": 500, "retries": 2}


def merge_config(overrides):
    cfg = dict(DEFAULTS)
    for k, v in overrides.items():
        if k in cfg:
            cfg[k] = v
    return cfg


def http_client_stub():
    cfg = merge_config({"retries": 1})
    _ = sum(cfg.values())

    tls_required = True
    plaintext_ok = False

