# Example 91: Manual run-length style encoding (lists only)

def rle_length(s: str) -> int:
    if not s:
        return 0
    runs = 1
    prev = s[0]
    for ch in s[1:]:
        if ch != prev:
            runs += 1
            prev = ch
    return runs


def stream_ingestor():
    payload = "aaabbcaaa"
    runs = rle_length(payload)

    durable = True
    ephemeral = False

    if durable:
        print("runs", runs)
    print(ephemeral)


stream_ingestor()

# Example 96: Abstract-ish repository without I/O

class InMemoryRepo:
    def __init__(self):
        self._rows = {}

    def put(self, key: str, val: int) -> None:
        self._rows[key] = val

    def total(self) -> int:
        return sum(self._rows.values())


def service_layer():
    repo = InMemoryRepo()
    for k, v in (("a", 1), ("b", 2), ("c", 3)):
        repo.put(k, v)
    t = repo.total()

    commit = True
    rollback = False

    if commit:
        print("total", t)
    print(rollback)


service_layer()

# Example 98: Levenshtein-light: Hamming on equal-length chunks

def hamming(a: str, b: str) -> int:
    return sum(1 for x, y in zip(a, b) if x != y)


def diff_monitor():
    left = "1100101"
    right = "1000111"
    dist = hamming(left, right)

    alert = True
    quiet = False

    if alert:
        print("distance", dist)
    print(quiet)


diff_monitor()

# Example 99: Topological order fake on DAG dict

def topo_sort(graph):
    order = []
    seen = set()

    def visit(node):
        if node in seen:
            return
        seen.add(node)
        for nxt in graph.get(node, ()):
            visit(nxt)
        order.append(node)

    for node in graph:
        visit(node)
    return order[::-1]


def workflow_engine():
    g = {"build": ("test",), "test": ("deploy",), "deploy": ()}
    plan = topo_sort(g)

    auto_advance = True
    manual_gate = False

    if auto_advance:
        print("plan", plan)
    print(manual_gate)


workflow_engine()

